results.final_sparql:
PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX crit: <http://purl.org/futuram/criticality#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX afn: <http://jena.apache.org/ARQ/function#>
SELECT (SUM(?kg) AS ?totalKg) (afn:sqrt(SUM(?sigma * ?sigma)) AS ?totalUnc) WHERE {
  SELECT DISTINCT ?constituent ?kg ?sigma WHERE {
    futuram:V0301030104_Y2020 fq:itemMass ?itemMass ;
               fq:contains [ fq:constituent ?constituent ; fq:amount ?frac ; fq:relativeUncertainty ?relUnc ] .
    BIND(?frac * ?itemMass AS ?kg)
    BIND(?relUnc * ?frac * ?itemMass AS ?sigma)
    ?constituent rdfs:subClassOf ?chebi . FILTER(CONTAINS(STR(?chebi), "CHEBI"))
    ?chebi crit:remark ?flag .
    FILTER NOT EXISTS {
      ?constituent rdfs:label ?label .
      FILTER(CONTAINS(LCASE(?label), "battery"))
    }
  }
}

